const r = $json;
if (!r.total || r.total === 0) return [];
return r.results.map(d => ({
  json: {
    dealId: d.id,
    dealName: d.properties.dealname || 'Sem nome',
    contatoNome: d.properties.contato_nome || '',
    contatoWhatsapp: d.properties.contato_whatsapp || '',
    segmento: d.properties.segmento || '',
    website: d.properties.website || '',
    pontoDeDor: d.properties.ponto_de_dor || '',
    canalOutbound: d.properties.canal_outbound || 'WhatsApp'
  }
}));

const d = $json;

const system = `Você é MIRA, CMO da Carbon Films — agência de marketing visual cinematográfico em Santa Catarina, Brasil. Analise os dados do prospect abaixo e crie um gancho personalizado para prospecção ativa via WhatsApp.

Regras:
- O gancho deve ser específico e baseado nos dados reais (não genérico)
- Tom consultivo, não vendedor — você identificou um problema, não quer 'vender algo'
- Máximo 2-3 frases para o gancho
- Não mencionar preço ou pacotes

Responda SOMENTE com JSON válido (sem markdown, sem explicação):
{
  "ponto_dor": "problema específico e observável (1-2 frases)",
  "gancho": "frase de abertura personalizada que NOVA vai usar",
  "tom": "direto|consultivo|descontraido|tecnico"
}`;

const user = `Empresa: ${d.dealName}\nSegmento: ${d.segmento}\nWebsite: ${d.website || 'não informado'}\nPonto de dor identificado: ${d.pontoDeDor || 'não especificado'}\nCanal de abordagem: ${d.canalOutbound}`;

return [{
  json: {
    ...d,
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-5',
      max_tokens: 512,
      system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const response = $json;
const prev = $('Preparar Prompt MIRA').first().json;

let mira = { ponto_dor: '', gancho: '', tom: 'consultivo' };
try {
  const text = response.content[0].text;
  mira = JSON.parse(text);
} catch(e) {
  mira.gancho = `Vi o trabalho de vocês na ${prev.dealName} e tenho uma ideia que pode ajudar — vale uma conversa rápida?`;
  mira.ponto_dor = prev.pontoDeDor || 'Oportunidade de melhoria na comunicação visual';
}

const now = Date.now();

return [{
  json: {
    ...prev,
    ganchoMira: mira.gancho,
    pontoDorValidado: mira.ponto_dor,
    tomRecomendado: mira.tom,
    hubspotUpdateBody: JSON.stringify({
      properties: {
        gancho_mira: mira.gancho,
        ponto_dor_validado: mira.ponto_dor,
        dealstage: $vars.HUBSPOT_STAGE_MSG_PRONTA
      }
    }),
    yanMsg: `[MIRA]: Pesquisa pronta para *${prev.dealName}*\n\nGancho: ${mira.gancho}\nPonto de dor: ${mira.ponto_dor}\nTom: ${mira.tom}\n\nAcesse o HubSpot, revise e avance para *Aprovado para Envio* quando estiver pronto.`
  }
}];
